import "./App.css";
import Slider from "./Slider";
import Nav from "./nav";

function App() {
  return (
    <div className="App">
      <head>
        <script
          src="https://unpkg.com/react@18/umd/react.development.js"
          crossorigin
        ></script>
        <script
          src="https://unpkg.com/react-dom@18/umd/react-dom.development.js"
          crossorigin
        ></script>
        <script src="https://unpkg.com/@babel/standalone/babel.min.js"></script>
      </head>
      <header>
        <h3 class="tomasRadic">TOMAS RADIC</h3>
        <Nav />
      </header>
      <body>
        <h1 class="tomRadText">Hello, I am Tomas Radic, front-End developer</h1>
        <Slider number={0} />
      </body>
    </div>
  );
}

export default App;
